                       {Array.isArray(ai.saran_pengembangan_spesifik) ? <ul className="list-decimal pl-3">{ai.saran_pengembangan_spesifik.map((s,i) => <li key={i} className="line-clamp-2">{s}</li>)}</ul> : (ai.saran || '-')}
