                                try {
                                  const res = await fetch(`/api/admin/submissions/${s.id}`, { method: 'DELETE' });
                                  if (res.ok) fetchData();
                                } catch (e) { alert('Hapus Gagal'); }
                              }}
                              className="text-red-400 hover:text-red-300 text-xs font-medium px-3 py-1.5 bg-red-500/10 hover:bg-red-500/20 rounded-lg inline-block transition-all"
                            >
                              Delete
                            </button>
                          </>
                        )}
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { NextResponse } from 'next/server';
import { addSubmission, updateSubmissionAiInsight } from '@/lib/dataStore';
import { generatePersonalityDescription } from '@/lib/gemini';

export async function POST(request) {
  try {
    const data = await request.json();
    const record = await addSubmission(data);

    // Optional: Backup to Google Sheets Webhook
    const webhookUrl = process.env.GOOGLE_SHEETS_WEBHOOK_URL;
    if (webhookUrl) {
      // Async fire-and-forget to avoid blocking response
      fetch(webhookUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(data),
      }).catch(err => console.error("Webhook Error:", err));
    }

    // We removed synchronous AI generation here to prevent Vercel 10s timeout errors. 
    // The client page.jsx now securely triggers the AI generation in a separate lightweight POST request 
    // immediately after this submit request succeeds.


    return NextResponse.json({ 
      success: true, 
      message: 'Assessment data saved successfully',
      data: { id: record.id }
    });
  } catch (error) {
    console.error("Error saving assessment result:", error);
    return NextResponse.json(
      { success: false, error: 'Failed to process assessment data' },
      { status: 500 }
    );
  }
}

